import{_ as o,o as e,c as r,ag as s}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"GitHub 配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/github.md","filePath":"guide/github.md","lastUpdated":1774839296000}'),n={name:"guide/github.md"};function a(i,t,l,c,g,d){return e(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="github-配置指南" tabindex="-1">GitHub 配置指南 <a class="header-anchor" href="#github-配置指南" aria-label="Permalink to &quot;GitHub 配置指南&quot;">​</a></h1><p>本文介绍如何使用 GitHub 作为远程仓库，完成仓库创建、Token 认证和软件配置。</p><h2 id="_1-创建远程仓库" tabindex="-1">1. 创建远程仓库 <a class="header-anchor" href="#_1-创建远程仓库" aria-label="Permalink to &quot;1. 创建远程仓库&quot;">​</a></h2><ol><li><p>访问 <a href="https://github.com/" target="_blank" rel="noopener noreferrer">GitHub</a> 注册并登录。</p></li><li><p>点击右上角「<strong>+</strong>」→「<strong>New repository</strong>」。</p></li></ol><ol start="3"><li>填写仓库名称（如 <code>my-sts-mods</code>），选择 <strong>Public</strong> 或 <strong>Private</strong>，点击「<strong>Create repository</strong>」。 <ul><li><strong>Public</strong> — 所有人可见，认证方式可选「免密」或「HTTPS」</li><li><strong>Private</strong> — 仅邀请的人可见，必须使用「HTTPS」或「SSH」认证</li></ul></li></ol><ol start="4"><li>仓库创建后，复制页面上的 HTTPS 地址（格式为 <code>https://github.com/用户名/仓库名.git</code>）。</li></ol><h2 id="_2-认证方式与-token-配置" tabindex="-1">2. 认证方式与 Token 配置 <a class="header-anchor" href="#_2-认证方式与-token-配置" aria-label="Permalink to &quot;2. 认证方式与 Token 配置&quot;">​</a></h2><h3 id="认证方式" tabindex="-1">认证方式 <a class="header-anchor" href="#认证方式" aria-label="Permalink to &quot;认证方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td><strong>免密</strong></td><td>仅适用于 Public 仓库，推送时弹出浏览器授权</td></tr><tr><td><strong>HTTPS</strong>（推荐）</td><td>适用于所有仓库，需要用户名 + Personal Access Token</td></tr><tr><td><strong>SSH</strong></td><td>已配置 SSH 密钥的用户可使用</td></tr></tbody></table><h3 id="创建-personal-access-token" tabindex="-1">创建 Personal Access Token <a class="header-anchor" href="#创建-personal-access-token" aria-label="Permalink to &quot;创建 Personal Access Token&quot;">​</a></h3><p>如果使用 HTTPS 认证（推荐），需要创建一个 Personal Access Token (PAT) 替代密码。</p><div class="tip custom-block"><p class="custom-block-title">公开仓库 + 免密</p><p>如果你的仓库是 <strong>Public</strong>，可以跳过此步骤，直接使用「免密」认证方式。但私有仓库必须配置 Token。</p></div><ol start="5"><li>点击右上角头像 →「<strong>Settings</strong>」→ 左侧栏最底部「<strong>Developer settings</strong>」→「<strong>Personal access tokens</strong>」→「<strong>Tokens (classic)</strong>」→「<strong>Generate new token (classic)</strong>」。</li></ol><ol start="6"><li><p>填写以下信息：</p><ul><li><strong>Note</strong>：填写备注，如 <code>Sync the Spire</code></li><li><strong>Expiration</strong>：选择过期时间（建议 90 天或 No expiration）</li><li><strong>Scopes</strong>：勾选 <code>repo</code>（完整仓库访问权限）</li></ul></li><li><p>点击「<strong>Generate token</strong>」，复制生成的 Token。</p></li></ol><div class="danger custom-block"><p class="custom-block-title">Token 仅显示一次</p><p>生成后立即复制保存，关闭页面后将无法再查看。如果遗忘，需要重新生成。</p></div><h2 id="_3-配置-sync-the-spire" tabindex="-1">3. 配置 Sync the Spire <a class="header-anchor" href="#_3-配置-sync-the-spire" aria-label="Permalink to &quot;3. 配置 Sync the Spire&quot;">​</a></h2><ol start="8"><li><p>打开 Sync the Spire，将复制的仓库地址粘贴到「远程仓库 URL」输入框，填写昵称。</p></li><li><p>认证方式选择「<strong>HTTPS</strong>」，填入你的 <strong>GitHub 用户名</strong>和刚才生成的 <strong>Token</strong>（作为密码）。</p></li><li><p>填写或自动查找游戏路径和存档路径，点击「<strong>保存并初始化</strong>」。</p></li></ol><h2 id="_4-邀请队友" tabindex="-1">4. 邀请队友 <a class="header-anchor" href="#_4-邀请队友" aria-label="Permalink to &quot;4. 邀请队友&quot;">​</a></h2><ol start="11"><li>进入仓库页面 →「<strong>Settings</strong>」→「<strong>Collaborators</strong>」→「<strong>Add people</strong>」，输入朋友的 GitHub 用户名发送邀请。</li></ol><ol start="12"><li>朋友接受邀请后，需要各自创建自己的 PAT，然后在 Sync the Spire 中填入仓库地址 + 自己的用户名和 Token。</li></ol>',20)])])}const u=o(n,[["render",a]]);export{p as __pageData,u as default};
